const contenido = $json.message.content;

function limpiar(texto) {
  return texto
    ?.toString()
    .replace(/["]/g, '')     // Elimina comillas dobles
    .replace(/\n/g, ' ')     // Reemplaza saltos de línea
    .replace(/\s+/g, ' ')    // Reduce espacios
    .trim();
}

return [
  {
    json: {
      mensaje_1: limpiar(contenido.mensaje_parte_1),
      mensaje_2: limpiar(contenido.mensaje_parte_2),
      mensaje_3: limpiar(contenido.mensaje_parte_3),
      mensaje_4: limpiar(contenido.mensaje_parte_4),
      tipo_respuesta: limpiar(contenido.tipo_respuesta),
      cantidad_de_mensajes: parseInt(contenido.cantidad_de_mensajes || "0", 10)
    }
  }
];

// Acceder al primer item de entrada
const inputData = $input.all();

// Función para verificar el estado de la IA
function verificarEstadoIA(item) {
  try {
    // Obtener los datos del item
    const data = item.json;

    // Acceder al lead (puede venir directamente o en un array)
    let lead;
    if (Array.isArray(data)) {
      lead = data[0]?._embedded?.leads?.[0];
    } else if (data._embedded?.leads) {
      lead = data._embedded.leads[0];
    } else {
      lead = data;
    }

    if (!lead) {
      return {
        ia_apagada: false,
        campo_existe: false,
        lead_id: null,
        error: "No se encontró el lead"
      };
    }

    // Buscar el campo "Apagar IA?"
    const customFields = lead.custom_fields_values || [];
    const campoApagarIA = customFields.find(
      field => field.field_name === "Apagar IA?"
    );

    // Resultado
    if (campoApagarIA) {
      const valor = campoApagarIA.values?.[0]?.value;
      return {
        ia_apagada: valor === true,
        campo_existe: true,
        lead_id: lead.id,
        lead_name: lead.name,
        lead_completo: lead
      };
    }

    // Si no existe el campo, IA está activa
    return {
      ia_apagada: false,
      campo_existe: false,
      lead_id: lead.id,
      lead_name: lead.name,
      lead_completo: lead
    };

  } catch (error) {
    return {
      ia_apagada: false,
      campo_existe: false,
      error: error.message
    };
  }
}

// Procesar todos los items
return inputData.map(item => {
  const resultado = verificarEstadoIA(item);
  return {
    json: resultado
  };
});

